templates.content:
// Fleet-wide fan-in: every scrape forwards to this one receiver so
// switching sinks only requires editing this single pipeline.
prometheus.remote_write "sink" {
  endpoint {
    url = "http://prom-sink:9091/api/v1/write"

    // Uncomment and fill in for authenticated sinks (Mimir Cloud, etc.)
    // basic_auth {
    //   username = sys.env("REMOTE_WRITE_USER")
    //   password = sys.env("REMOTE_WRITE_PASS")
    // }
  }
}

// Alloy exposes its own metrics on 0.0.0.0:12345/metrics by default.
// Static target keeps this working inside remotecfg-delivered modules,
// where prometheus.exporter.self has surfaced quirks in the past.
prometheus.scrape "alloy_self" {
  targets = [{
    "__address__"      = "127.0.0.1:12345",
    "__metrics_path__" = "/metrics",
    "job"              = "alloy",
  }]
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "15s"
}

// node_exporter lives inside Alloy as prometheus.exporter.unix.
// We enable the conservative default collector set; tune via the
// `include_*` / `exclude_*` args if you need more/fewer metrics.
prometheus.exporter.unix "default" {
}

prometheus.scrape "node" {
  targets         = prometheus.exporter.unix.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// The DSN is read from the collector's environment; never bake secrets
// into pipeline content (they'd be readable by everyone with `read`
// scope on /pipelines).
prometheus.exporter.postgres "default" {
  data_source_names = [sys.env("POSTGRES_DSN")]
}

prometheus.scrape "postgres" {
  targets         = prometheus.exporter.postgres.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

prometheus.exporter.elasticsearch "default" {
  address = sys.env("ELASTICSEARCH_URL")
  // Flip these on if you want per-index / per-shard cardinality:
  // indices        = true
  // indices_settings = true
  // cluster_settings = true
  // shards         = true
}

prometheus.scrape "elasticsearch" {
  targets         = prometheus.exporter.elasticsearch.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// nginx-prometheus-exporter is a separate process — Alloy just scrapes
// its /metrics. Default port is 9113.
prometheus.scrape "nginx" {
  targets = [{
    "__address__"      = coalesce(sys.env("NGINX_EXPORTER_ADDR"), "localhost:9113"),
    "__metrics_path__" = "/metrics",
    "job"              = "nginx",
  }]
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

discovery.kubernetes "pods" {
  role = "pod"
}

discovery.relabel "pods" {
  targets = discovery.kubernetes.pods.targets

  // Only keep pods that have prometheus.io/scrape="true".
  rule {
    source_labels = ["__meta_kubernetes_pod_annotation_prometheus_io_scrape"]
    action        = "keep"
    regex         = "true"
  }

  // Honor prometheus.io/path if set.
  rule {
    source_labels = ["__meta_kubernetes_pod_annotation_prometheus_io_path"]
    action        = "replace"
    target_label  = "__metrics_path__"
    regex         = "(.+)"
  }

  // Honor prometheus.io/port if set, rewriting the scrape address.
  rule {
    source_labels = ["__address__", "__meta_kubernetes_pod_annotation_prometheus_io_port"]
    action        = "replace"
    target_label  = "__address__"
    regex         = "([^:]+)(?::\\d+)?;(\\d+)"
    replacement   = "$1:$2"
  }

  // Surface useful pod metadata as labels.
  rule {
    source_labels = ["__meta_kubernetes_namespace"]
    target_label  = "namespace"
  }
  rule {
    source_labels = ["__meta_kubernetes_pod_name"]
    target_label  = "pod"
  }
}

prometheus.scrape "k8s_pods" {
  targets         = discovery.relabel.pods.output
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// Forwards everything; filter via relabel if you want to drop noisy
// units. The `host` label matches the convention used by the rest of
// the Grafana ecosystem.
loki.source.journal "system" {
  forward_to    = [loki.write.sink.receiver]
  labels        = { host = sys.env("HOSTNAME"), job = "systemd-journal" }
  max_age       = "12h"
}

discovery.docker "containers" {
  host = "unix:///var/run/docker.sock"
}

loki.source.docker "containers" {
  host       = "unix:///var/run/docker.sock"
  targets    = discovery.docker.containers.targets
  forward_to = [loki.write.sink.receiver]
  labels     = { job = "docker" }
}

otelcol.receiver.otlp "default" {
  grpc {
    endpoint = "0.0.0.0:4317"
  }
  http {
    endpoint = "0.0.0.0:4318"
  }

  output {
    traces = [otelcol.exporter.otlp.remote.input]
  }
}

otelcol.exporter.otlp "remote" {
  client {
    endpoint = sys.env("OTLP_EXPORT_ENDPOINT")

    // If your remote is TLS-terminated, flip this:
    // tls {
    //   insecure = false
    // }
    tls {
      insecure = true
    }
  }
}

// Fleet-wide logs fan-in: every log source forwards to this one
// receiver so changing destinations only requires editing this single
// pipeline. Mirrors the `remote-write-sink` pattern for metrics.
loki.write "sink" {
  endpoint {
    url = coalesce(sys.env("LOKI_WRITE_URL"), "http://loki:3100/loki/api/v1/push")

    // Uncomment for authenticated Loki (Grafana Cloud, multi-tenant):
    // basic_auth {
    //   username = sys.env("LOKI_USER")
    //   password = sys.env("LOKI_PASS")
    // }
    // tenant_id = sys.env("LOKI_TENANT")
  }

  // Apply fleet-wide labels here so individual sources don't have to.
  external_labels = {
    cluster = coalesce(sys.env("CLUSTER"), "default"),
  }
}

// Fleet-wide traces fan-in. Other pipelines reference this as
// `otelcol.exporter.otlp.sink.input`; repoint here to switch backends.
otelcol.exporter.otlp "sink" {
  client {
    endpoint = coalesce(sys.env("TEMPO_OTLP_ENDPOINT"), "tempo:4317")

    // For TLS-terminated remotes flip insecure=false and provide CAs:
    // tls {
    //   insecure = false
    //   ca_file  = sys.env("TEMPO_CA_FILE")
    // }
    tls {
      insecure = true
    }

    // Multi-tenant Tempo / Grafana Cloud Traces — pass the tenant header:
    // headers = {
    //   "X-Scope-OrgID" = sys.env("TEMPO_TENANT"),
    // }
  }
}

// Authenticated remote_write sink for Grafana Cloud Metrics / Mimir /
// Cortex. The component is named `mimir_sink` so it doesn't clash with
// the unauthenticated `remote-write-sink` template — pipelines that
// want to ship to BOTH targets can list both receivers in forward_to.
prometheus.remote_write "mimir_sink" {
  endpoint {
    url = sys.env("MIMIR_REMOTE_WRITE_URL")

    basic_auth {
      username = sys.env("MIMIR_USER")
      password = sys.env("MIMIR_PASS")
    }

    // Multi-tenant Mimir / Cortex requires the X-Scope-OrgID header:
    // headers = {
    //   "X-Scope-OrgID" = sys.env("MIMIR_TENANT"),
    // }
  }
}

prometheus.exporter.redis "default" {
  redis_addr = sys.env("REDIS_ADDR")

  // Uncomment for password-protected Redis instances:
  // redis_password = sys.env("REDIS_PASSWORD")
}

prometheus.scrape "redis" {
  targets         = prometheus.exporter.redis.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

prometheus.exporter.mysql "default" {
  data_source_name = sys.env("MYSQL_DSN")
}

prometheus.scrape "mysql" {
  targets         = prometheus.exporter.mysql.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

prometheus.exporter.mongodb "default" {
  mongodb_uri = sys.env("MONGODB_URI")
}

prometheus.scrape "mongodb" {
  targets         = prometheus.exporter.mongodb.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// windows_exporter lives inside Alloy as prometheus.exporter.windows.
// The default collector set covers the common ground; extend via
// `enabled_collectors` if you need IIS, MSSQL, ScheduledTask, etc.
prometheus.exporter.windows "default" {
}

prometheus.scrape "windows" {
  targets         = prometheus.exporter.windows.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// cAdvisor introspects the host's cgroup hierarchy automatically.
// On Docker hosts, mount /var/lib/docker (read-only) and /sys/fs/cgroup
// into the Alloy container so labels include image/container names.
prometheus.exporter.cadvisor "default" {
}

prometheus.scrape "cadvisor" {
  targets         = prometheus.exporter.cadvisor.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// HTTP/TCP synthetic probes. Edit the `target` blocks to point at
// your own services; modules are reusable across targets.
prometheus.exporter.blackbox "default" {
  config = `
modules:
  http_2xx:
    prober: http
    timeout: 5s
    http:
      preferred_ip_protocol: ip4
      valid_status_codes: [200, 201, 204]
  tcp_connect:
    prober: tcp
    timeout: 5s
`

  target {
    name    = "example-http"
    address = "https://example.com"
    module  = "http_2xx"
  }
}

prometheus.scrape "blackbox" {
  targets         = prometheus.exporter.blackbox.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "60s"
}

prometheus.exporter.kafka "default" {
  kafka_uris = [coalesce(sys.env("KAFKA_BROKER"), "localhost:9092")]

  // For multi-broker clusters, list them explicitly:
  // kafka_uris = ["broker1:9092", "broker2:9092", "broker3:9092"]
}

prometheus.scrape "kafka" {
  targets         = prometheus.exporter.kafka.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// Alloy doesn't bundle a RabbitMQ exporter — RabbitMQ 3.8+ exposes
// metrics natively when the rabbitmq_prometheus plugin is enabled
// (default port 15692). For older versions, run rabbitmq_exporter as
// a sidecar and point this at it.
prometheus.scrape "rabbitmq" {
  targets = [{
    "__address__"      = coalesce(sys.env("RABBITMQ_METRICS_ADDR"), "localhost:15692"),
    "__metrics_path__" = "/metrics",
    "job"              = "rabbitmq",
  }]
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// Edit the `comm` array to track different processes; one series per
// matched process group is created. Drop the matcher to track every
// process (high cardinality — be careful in production).
prometheus.exporter.process "default" {
  matcher {
    name = "{{.Comm}}"
    comm = ["nginx", "redis-server", "postgres", "alloy"]
  }
}

prometheus.scrape "process" {
  targets         = prometheus.exporter.process.default.targets
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// Discover the kube-state-metrics endpoint and scrape it. Adjust the
// namespace/service-name regexes if your install uses non-defaults.
discovery.kubernetes "ksm" {
  role = "endpoints"
  namespaces {
    names = ["kube-system"]
  }
}

discovery.relabel "ksm" {
  targets = discovery.kubernetes.ksm.targets

  rule {
    source_labels = ["__meta_kubernetes_service_name"]
    action        = "keep"
    regex         = "kube-state-metrics"
  }
  rule {
    source_labels = ["__meta_kubernetes_endpoint_port_name"]
    action        = "keep"
    regex         = "http-metrics"
  }
}

prometheus.scrape "ksm" {
  targets         = discovery.relabel.ksm.output
  forward_to      = [prometheus.remote_write.sink.receiver]
  scrape_interval = "30s"
}

// Edit the path globs to scope the file set. local.file_match watches
// the filesystem so newly created files are picked up automatically.
local.file_match "varlog" {
  path_targets = [
    { __path__ = "/var/log/*.log" },
    { __path__ = "/var/log/**/*.log" },
  ]
}

loki.source.file "varlog" {
  targets    = local.file_match.varlog.targets
  forward_to = [loki.write.sink.receiver]
}

// Discover all pods cluster-wide and tail their logs. Add an extra
// keep-rule in discovery.relabel if you want to scope to specific
// namespaces or annotation patterns.
discovery.kubernetes "pods_logs" {
  role = "pod"
}

discovery.relabel "pods_logs" {
  targets = discovery.kubernetes.pods_logs.targets

  rule {
    source_labels = ["__meta_kubernetes_namespace"]
    target_label  = "namespace"
  }
  rule {
    source_labels = ["__meta_kubernetes_pod_name"]
    target_label  = "pod"
  }
  rule {
    source_labels = ["__meta_kubernetes_pod_container_name"]
    target_label  = "container"
  }
}

loki.source.kubernetes "pods" {
  targets    = discovery.relabel.pods_logs.output
  forward_to = [loki.write.sink.receiver]
}

// Tails the Application event log. Duplicate this block with a
// different `eventlog_name` to also tail System, Security, etc.
loki.source.windowsevent "application" {
  eventlog_name = "Application"
  forward_to    = [loki.write.sink.receiver]
  labels        = {
    host    = sys.env("HOSTNAME"),
    job     = "windowsevent",
    channel = "Application",
  }
}

// Zipkin v2 ingress. Forwards into the shared traces sink so the
// Zipkin clients in your fleet can keep emitting Zipkin while the
// backend is Tempo / any OTLP destination.
otelcol.receiver.zipkin "default" {
  endpoint = "0.0.0.0:9411"

  output {
    traces = [otelcol.exporter.otlp.sink.input]
  }
}
